se if (choice == &#x27;n&#x27;)            &#123;                printf(&quot;谢谢使用，bye!&quot;);                return 0;            &#125;            else            &#123;                printf(&quot;选择错误，请重新选择！\n&quot;);                while (getchar() != &#x27;\n&#x27;);            &#125;        &#125;    &#125;    return 0;&#125;

