菜单选择，输入科目名称，单独输出该科统计信息 #include &lt;stdio.h&gt;#include &lt;string.h&gt;#define COWS 3    // 最多学生人数#define COLS 4    // 科目数量#define SUM_AVG 2 // 总分、平均分int main()&#123;    char name[COWS][20];    char sub[COLS][20] = &#123;&quot;语文&quot;, &quot;数学&quot;, &quot;英语&quot;, &quot;地理&quot;&#125;;    float score[COWS][COLS];    float sum_avg[COWS][SUM_AVG] = &#123;0.00&#125;;    int count = 0;    // ==========第一步：批量录入所有学生姓名==========    printf(&quot;=====录入学生姓名=====\n&quot;);    while (1)    &#123;        if (count &gt;= COWS)        &#123;            printf(&quot;学生数量已达上限！\n&quot;);            break;        &#125;        char tmp[20];        printf(&quot;请输入第%d个学生姓名(输入exit结束姓名录入)：&quot;, count + 1);        fgets(tmp, sizeof(tmp), stdin);        tmp[strcspn(tmp, &quot;\n&quot;)] = &#x27;\0&#x27;;        if (!strcmp(tmp, &quot;exit&quot;))            break;        if (strlen(tmp) == 0)        &#123;            printf(&quot;姓名不能为空，请重新输入\n&quot;);            continue;        &#125;        strcpy(name[count], tmp);        count++;    &#125;    if (count == 0)    &#123;        printf(&quot;未录入任何学生，程序退出\n&quot;);        return 0;    &#125;    // ==========第二步：统一录入所有学生各科成绩==========    printf(&quot;\n=====录入学生各科成绩=====\n&quot;);    for (int i = 0; i &lt; count; i++)    &#123;        sum_avg[i][0] = 0;        for (int j = 0; j &lt; COLS; j++)        &#123;            float s;            printf(&quot;请输入【%s】的%s成绩：&quot;, name[i], sub[j]);            while (1)            &#123;                while (!scanf(&quot;%f&quot;, &amp;s))                &#123;                    printf(&quot;输入非法，请重新输入成绩：&quot;);                    while (getchar() != &#x27;\n&#x27;);                &#125;                if (s &lt; 0 || s &gt; 100)                &#123;                    printf(&quot;成绩范围0~100，请重输：&quot;);                    continue;                &#125;                break;            &#125;            score[i][j] = s;            sum_avg[i][0] += s;        &#125;        sum_avg[i][1] = sum_avg[i][0] / COLS;    &#125;    // ==========打印全部学生总表==========    printf(&quot;\n================学生成绩总表================\n&quot;);    printf(&quot;%-10s&quot;, &quot;姓名&quot;);    for (int i = 0; i &lt; COLS; i++)        printf(&quot;%-10s&quot;, sub[i]);    printf(&quot;%-10s%-10s\n&quot;, &quot;总分&quot;, &quot;平均分&quot;);    for (int i = 0; i &lt; count; i++)    &#123;        printf(&quot;%-10s&quot;, name[i]);        for (int j = 0; j &lt; COLS; j++)            printf(&quot;%-10.2f&quot;, score[i][j]);        printf(&quot;%-10.2f%-10.2f\n&quot;, sum_avg[i][0], sum_avg[i][1]);    &#125;    // ==========菜单功能：查询指定科目统计==========    int menu;    while (1)    &#123;        printf(&quot;\n=====功能菜单=====\n&quot;);        printf(&quot;1. 查询单科成绩统计\n&quot;);        printf(&quot;0. 退出程序\n&quot;);        printf(&quot;请输入功能选择：&quot;);        scanf(&quot;%d&quot;, &amp;menu);        if (menu == 0)        &#123;            printf(&quot;程序结束\n&quot;);            break;        &#125;        if (menu != 1)        &#123;            printf(&quot;输入错误，请重新选择\n&quot;);            continue;        &#125;        // 查询单科        char searchSub[20];        getchar();        printf(&quot;请输入要查询的科目名称(语文/数学/英语/地理)：&quot;);        fgets(searchSub, sizeof(searchSub), stdin);        searchSub[strcspn(searchSub, &quot;\n&quot;)] = &#x27;\0&#x27;;        // 匹配科目下标        int subIdx = -1;        for (int i = 0; i &lt; COLS; i++)        &#123;            if (!strcmp(searchSub, sub[i]))            &#123;                subIdx = i;                break;            &#125;        &#125;        if (subIdx == -1)        &#123;            printf(&quot;不存在该科目！\n&quot;);            continue;        &#125;        // 统计该科目数据        float total = 0;        float maxScore = score[0][subIdx];        float minScore = score[0][subIdx];        char maxName[20], minName[20];        strcpy(maxName, name[0]);        strcpy(minName, name[0]);        for (int i = 0; i &lt; count; i++)        &#123;            float s = score[i][subIdx];            total += s;            if (s &gt; maxScore)            &#123;                maxScore = s;                strcpy(maxName, name[i]);            &#125;            if (s &lt; minScore)            &#123;                minScore = s;                strcpy(minName, name[i]);            &#125;        &#125;        float avg = total / count;        // 输出单科统计        printf(&quot;\n=====%s科目统计结果=====\n&quot;, sub[subIdx]);        printf(&quot;科目总分：%.2f\n&quot;, total);        printf(&quot;科目平均分：%.2f\n&quot;, avg);        printf(&quot;最高分：%.2f，学生：%s\n&quot;, maxScore, maxName);        printf(&quot;最低分：%.2f，学生：%s\n&quot;, minScore, minName);    &#125;    return 0;&#125;

一、结构体 struct
1. 核心作用
单个结构体变量可存储多种不同数据类型（学生信息：姓名char、年龄int、分数float），是开发最常用自定义类型。
2. 完整语法规则
（1）定义结构体类型
struct 结构体名&#123;    类型1 成员名1;    类型2 成员名2;    ...&#125; 全局变量1, 全局变量2; // 末尾可直接定义全局结构体变量
struct 结构体名 整体代表结构体类型。
#include &lt;stdio.h&gt;// 定义结构体类型struct Student &#123;    int id;              // 学号    char name[20];       // 姓名    int age;             // 年龄    struct &#123;             // 嵌套结构体：生日        int year;        int month;        int day;    &#125; birth;    float score;         // 成绩&#125; s1;  // 同时定义全局变量s1
（2）定义结构体变量
// 方式1：单独定义struct Student s1;// 方式2：定义类型同时创建变量struct Student&#123;char name[20];int age;&#125; s2;// 方式3：使用typedef简化（见第五章）typedef struct Student Stu;Stu s3;
（3）初始化
// 顺序初始化，按成员顺序赋值struct Student s = &#123;&quot;张三&quot;, 18, 95.5f&#125;;// 指定成员初始化（C99）struct Student s2 = &#123;.name = &quot;李四&quot;, .age = 19&#125;;// 嵌套结构体初始化struct Student s3 = &#123;    1001,     &quot;wang&quot;,    23,     &#123;1988, 3, 4&#125;,  // 嵌套结构体初始化    88.5f&#125;;// 同类型结构体直接整体赋值struct Student s4 = s3;
（4）访问成员

普通变量：结构体变量.成员名
结构体指针：结构体指针-&gt;成员名

#include &lt;stdio.h&gt;#include &lt;string.h&gt;struct Student &#123;    int id;    char name[20];    int age;    float score;&#125;;int main() &#123;    struct Student s1 = &#123;1001, &quot;张三&quot;, 20, 88.5f&#125;;    struct Student *p = &amp;s1;        // 普通变量访问    printf(&quot;学号: %d\n&quot;, s1.id);    printf(&quot;姓名: %s\n&quot;, s1.name);        // 指针访问（两种方式）    printf(&quot;年龄: %d\n&quot;, (*p).age);   // 方式1：解引用    printf(&quot;成绩: %.1f\n&quot;, p-&gt;score); // 方式2：箭头操作符（推荐）        return 0;&#125;
（5）内存对齐三大规则（必考）

结构体整体起始地址 = 最大成员字节数整数倍；
每个成员起始偏移 = 自身类型字节整数倍；
结构体总大小 = 最大成员字节数整数倍（末尾补填充字节）。

#include &lt;stdio.h&gt;// 演示内存对齐struct A &#123;    int a;          // 4字节，偏移0    char b[11];     // 11字节，偏移4（对齐到4的倍数）    int c;          // 4字节，偏移16（对齐到4的倍数）    double d;       // 8字节，偏移24（对齐到8的倍数）    char e;         // 1字节，偏移32    // 总大小40（填充到8的倍数）&#125;;struct B &#123;    char a;         // 1字节，偏移0    int b;          // 4字节，偏移4（对齐到4的倍数）    char c[5];      // 5字节，偏移8    int d[3];       // 12字节，偏移16（对齐到4的倍数）    double f;       // 8字节，偏移32（对齐到8的倍数）    char g;         // 1字节，偏移40    // 总大小48（填充到8的倍数）&#125;;int main() &#123;    printf(&quot;结构体A大小: %lld字节\n&quot;, sizeof(struct A));    printf(&quot;结构体B大小: %lld字节\n&quot;, sizeof(struct B));        // 查看各成员地址，观察对齐    struct B ob;    printf(&quot;\n结构体B各成员地址:\n&quot;);    printf(&quot;ob.a 地址: %p\n&quot;, &amp;ob.a);    printf(&quot;ob.b 地址: %p\n&quot;, &amp;ob.b);    printf(&quot;ob.c 地址: %p\n&quot;, ob.c);    printf(&quot;ob.d 地址: %p\n&quot;, ob.d);    printf(&quot;ob.f 地址: %p\n&quot;, &amp;ob.f);    printf(&quot;ob.g 地址: %p\n&quot;, &amp;ob.g);        return 0;&#125;
（6）位域（位段）
仅支持char/short/int整型，指定二进制占用位数，节省内存；不能取地址&amp;。
语法：类型 成员:二进制位数;
#include &lt;stdio.h&gt;// 位域示例：颜色使用32位精确控制struct Color &#123;    int red:8;      // 使用8位存储红色分量（0-255）    int green:8;    // 使用8位存储绿色分量（0-255）    int blue:8;     // 使用8位存储蓝色分量（0-255）    int alpha:8;    // 使用8位存储透明度（0-255）&#125;;  // 总共32位，占4字节int main() &#123;    struct Color c;    c.red = 0x12;    c.green = 0x34;    c.blue = 0x56;    c.alpha = 0x78;        printf(&quot;Color结构体大小: %lld字节\n&quot;, sizeof(struct Color));    // 虽然每个成员只占8位，但总共32位，所以占4字节        // &amp;c.red;  // 错误！位域不能取地址        return 0;&#125;
（7）结构体数组与指针

数组：struct Student arr[5];，取值arr[0].age
指针：struct Student *p = &amp;s;，取值p-&gt;name

#include &lt;stdio.h&gt;struct Book &#123;    int id;    float price;    char name[20];&#125;;// 使用const指针保护数据不被修改void print_book(const struct Book *b) &#123;    printf(&quot;书籍ID: %d\n&quot;, b-&gt;id);    printf(&quot;书籍价格: %.2f\n&quot;, b-&gt;price);    printf(&quot;书籍名称: %s\n&quot;, b-&gt;name);    // b-&gt;id = 9999;  // 这行会报错，因为const保护&#125;int main() &#123;    // 结构体数组初始化    struct Book arr[5] = &#123;        &#123;1001, 11.1f, &quot;C++&quot;&#125;,        &#123;1002, 22.2f, &quot;Java&quot;&#125;    &#125;;        printf(&quot;数组大小: %lld\n&quot;, sizeof(arr) / sizeof(arr[0]));        // 结构体赋值（值拷贝）    arr[4] = arr[1];    printf(&quot;arr[4]的价格: %.2f\n&quot;, arr[4].price);        // 数组名是首元素地址    printf(&quot;arr的地址: %p\n&quot;, arr);    printf(&quot;arr+1的地址: %p\n&quot;, arr + 1);        // 结构体指针    struct Book *p = arr;  // 指向数组首元素    printf(&quot;通过指针访问: %s\n&quot;, p-&gt;name);        // 传递指针给函数    print_book(arr + 1);        return 0;&#125;
3. const修饰指针区分（易混难点）
int bb=10,cc=20;// 1.const修饰*：内容不可改，指针可改const int *pp1 = &amp;bb;pp1 = &amp;cc;   // 合法// *pp1 = 100; 非法，不能修改指向的值// 2.int const * 等价 const int *int const *pp2 = &amp;bb;// 3.const修饰指针变量：指针不可改，内容可改int *const pp3 = &amp;bb;// pp3 = &amp;cc; 非法，指针指向固定*pp3 = 100; // 合法// 4.双const：指针和内容都不能修改const int *const pp4 = &amp;bb;// pp4=&amp;cc; *pp4=100; 全部非法
口诀：**const在*前，值不能改；const在变量名前，指针不能改**。
4.
结构体完整例题（学生信息管理）
#include &lt;stdio.h&gt;#include &lt;string.h&gt;// 定义结构体struct Student&#123;    char name[20];    int age;    float score;    // 位域示例：性别只用1bit存储 0女 1男    unsigned int sex:1;&#125;;// 结构体作为函数参数（值传递）void printStu(struct Student s)&#123;    printf(&quot;姓名：%s 年龄：%d 分数：%.1f 性别：%s\n&quot;,           s.name, s.age, s.score, s.sex?&quot;男&quot;:&quot;女&quot;);&#125;// 结构体指针作为参数（引用传递，效率更高）void modifyScore(struct Student *p, float newScore)&#123;    p-&gt;score = newScore;  // 直接修改原数据&#125;int main()&#123;    // 初始化    struct Student s1 = &#123;&quot;李四&quot;, 19, 88.0f, 1&#125;;    struct Student s2;    strcpy(s2.name, &quot;小红&quot;);    s2.age = 18;    s2.score = 92.5f;    s2.sex = 0;    // 结构体整体赋值    struct Student s3 = s1;    // 结构体指针    struct Student *p = &amp;s2;    printf(&quot;指针访问姓名：%s\n&quot;, p-&gt;name);        // 通过指针修改    modifyScore(&amp;s2, 95.0f);    // 结构体数组    struct Student stuArr[2] = &#123;s1, s2&#125;;    printf(&quot;数组学生分数：%.1f\n&quot;, stuArr[0].score);    printStu(s1);    printStu(s2);    return 0;&#125;
5. 内存对齐例题
#include &lt;stdio.h&gt;struct Test&#123;    char a;  //1字节    int b;   //4字节    short c; //2字节&#125;;int main()&#123;    // 最大成员int占4字节，总大小填充至4倍数    printf(&quot;结构体大小：%d\n&quot;, sizeof(struct Test)); //输出12    return 0;&#125;
二、联合体 union（共用体）
1. 核心特点
所有成员共享同一块内存，同一时间只能存一个成员；总大小=最大成员所占字节，遵循对齐规则。
2. 基础语法
union 联合体名&#123;    类型1 成员1;    类型2 成员2;&#125;;// 定义变量union Data d;// 访问d.num = 100;d.ch = &#x27;A&#x27;; // 覆盖上面num的数据
#include &lt;stdio.h&gt;#include &lt;string.h&gt;// 联合体：所有成员共享同一块内存union Score &#123;    int chinese;      // 4字节    float english;    // 4字节    char math[15];    // 15字节&#125;;  // 大小为最大成员的大小（对齐后为16字节）int main() &#123;    printf(&quot;联合体Score大小: %lld字节\n&quot;, sizeof(union Score));    // 输出16（char数组最大，对齐到4的倍数）        union Score s;    s.chinese = 95;    printf(&quot;语文成绩: %d\n&quot;, s.chinese);        s.english = 88.5f;  // 覆盖chinese    printf(&quot;英语成绩: %.1f\n&quot;, s.english);        strcpy(s.math, &quot;A+&quot;);  // 覆盖english    printf(&quot;数学成绩: %s\n&quot;, s.math);        return 0;&#125;
3.
联合体应用：类型安全的成绩存储
#include &lt;stdio.h&gt;#include &lt;string.h&gt;// 使用联合体存储不同类型的成绩struct MyScore &#123;    int type;  // 0:语文(int), 1:英语(float), 2:数学(string)    union &#123;        int chinese;        float english;        char math[15];    &#125;;&#125;;// 根据类型显示成绩void showScore(struct MyScore s) &#123;    switch (s.type) &#123;        case 0:            printf(&quot;语文成绩: %d\n&quot;, s.chinese);            break;        case 1:            printf(&quot;英语成绩: %.2f\n&quot;, s.english);            break;        case 2:            printf(&quot;数学成绩: %s\n&quot;, s.math);            break;        default:            printf(&quot;未知类型\n&quot;);    &#125;&#125;int main() &#123;    // 三种不同类型的成绩    struct MyScore s1, s2, s3;        // 英语成绩（浮点数）    s1.english = 88.5f;    s1.type = 1;        // 语文成绩（整数）    s2.chinese = 95;    s2.type = 0;        // 数学成绩（字符串）    strcpy(s3.math, &quot;A+&quot;);    s3.type = 2;        // 显示成绩    showScore(s1);    showScore(s2);    showScore(s3);        return 0;&#125;
4.
联合体例题（判断数据存储大小端）
#include &lt;stdio.h&gt;union Endian&#123;    int num;    char ch;&#125;;int main()&#123;    union Endian u;    u.num = 1;    if(u.ch == 1)        printf(&quot;小端存储\n&quot;);    else        printf(&quot;大端存储\n&quot;);    return 0;&#125;
5. 联合体高级示例：内存共享观察
#include &lt;stdio.h&gt;union A &#123;    int a;      // 4字节    short b;    // 2字节    char c;     // 1字节&#125;;int main() &#123;    union A oa;    oa.a = 0x12345678;        printf(&quot;存储0x12345678后:\n&quot;);    printf(&quot;oa.a = %x\n&quot;, oa.a);  // 12345678    printf(&quot;oa.b = %x\n&quot;, oa.b);  // 5678（低16位）    printf(&quot;oa.c = %x\n&quot;, oa.c);  // 78（低8位）    // 在小端系统中，低地址存低位        printf(&quot;\n联合体A大小: %lld字节\n&quot;, sizeof(union A));  // 4字节        // 联合体数组和指针    union A s[10];    union A *ps = s;    ps-&gt;a = 100;  // 访问第一个元素        return 0;&#125;
三、枚举 enum
1. 作用
限定变量只能取预设常量，提升代码可读性（星期、性别、状态码）。
2. 语法规则
enum 枚举名&#123;    常量1,      // 默认0    常量2=5,    // 手动赋值5    常量3       // 自动+1=6&#125;;// 定义变量enum Week w = MON;
#include &lt;stdio.h&gt;// 枚举：定义一组命名的整型常量enum Week &#123;    MON,        // 默认0    TUES = 123, // 显式赋值123    WED,        // 124（自动递增）    THUR = -999, // 显式赋值-999    FRI,        // -998（自动递增）    SATU,       // -997    SUN         // -996&#125;;// 枚举的实际应用enum Color &#123;    RED,    GREEN,    BLUE&#125;;int main() &#123;    // 查看枚举值    printf(&quot;MON = %d\n&quot;, MON);    printf(&quot;TUES = %d\n&quot;, TUES);    printf(&quot;WED = %d\n&quot;, WED);    printf(&quot;THUR = %d\n&quot;, THUR);    printf(&quot;FRI = %d\n&quot;, FRI);    printf(&quot;SATU = %d\n&quot;, SATU);    printf(&quot;SUN = %d\n&quot;, SUN);    // 声明枚举变量    enum Week w;    w = THUR;    printf(&quot;w = %d\n&quot;, w);        return 0;&#125;
3. 枚举应用：状态管理
#include &lt;stdio.h&gt;// 游戏状态枚举enum GameState &#123;    MENU,       // 主菜单    PLAYING,    // 游戏中    PAUSED,     // 暂停    GAMEOVER    // 游戏结束&#125;;// 颜色枚举enum Color &#123;    RED,    GREEN,    BLUE&#125;;// 使用枚举作为函数参数void print_color(enum Color c) &#123;    switch(c) &#123;        case RED:   printf(&quot;红色\n&quot;); break;        case GREEN: printf(&quot;绿色\n&quot;); break;        case BLUE:  printf(&quot;蓝色\n&quot;); break;        default:    printf(&quot;未知颜色\n&quot;);    &#125;&#125;void print_state(enum GameState state) &#123;    switch(state) &#123;        case MENU:     printf(&quot;主菜单\n&quot;); break;        case PLAYING:  printf(&quot;游戏中\n&quot;); break;        case PAUSED:   printf(&quot;暂停\n&quot;); break;        case GAMEOVER: printf(&quot;游戏结束\n&quot;); break;    &#125;&#125;int main() &#123;    enum GameState currentState = MENU;    print_state(currentState);        currentState = PLAYING;    print_state(currentState);        // 枚举应用    enum Color c = RED;    print_color(c);    print_color(GREEN);        return 0;&#125;
四、typedef 类型重命名
1. 作用
给已有类型起别名，简化代码、提升移植性。
通用技巧：去掉typedef，剩余代码定义什么变量，别名就是对应类型。
2. 基础示例
typedef int INT;        // INT等价inttypedef char ARR[20];   // ARR等价char[20]typedef struct Student Stu; // Stu代替struct Studenttypedef struct Student * StuP; // 结构体指针别名
#include &lt;stdio.h&gt;// 基础类型别名typedef int Integer;typedef float Float;// 数组类型别名typedef char String[20];// 结构体类型别名typedef struct &#123;    int id;    char name[10];&#125; Student;// 结构体指针别名typedef Student* StudentPtr;// 函数指针类型别名typedef int (*CompareFunc)(int, int);int main() &#123;    Integer num = 100;    String str = &quot;Hello&quot;;    Student s = &#123;1001, &quot;小明&quot;&#125;;    StudentPtr p = &amp;s;        printf(&quot;num: %d\n&quot;, num);    printf(&quot;str: %s\n&quot;, str);    printf(&quot;学号：%d 姓名：%s\n&quot;, p-&gt;id, p-&gt;name);        return 0;&#125;
五、综合实战大题（融合全部自定义类型）
需求：定义学生结构体（包含性别枚举、分数联合体、typedef简化），批量录入打印学生信息。
#include &lt;stdio.h&gt;#include &lt;string.h&gt;// 枚举：性别enum Sex&#123;MAN, WOMAN&#125;;// 联合体：分数（整数/浮点两种计分）union Score&#123;    int intScore;    float floatScore;&#125;;// typedef简化结构体typedef struct&#123;    char name[15];    enum Sex sex;    union Score sc;&#125; Student;void showStu(Student s)&#123;    printf(&quot;姓名：%s 性别：%s &quot;, s.name, s.sex==MAN?&quot;男&quot;:&quot;女&quot;);    printf(&quot;整数成绩：%d 浮点成绩：%.1f\n&quot;, s.sc.intScore, s.sc.floatScore);&#125;int main()&#123;    Student s1;    strcpy(s1.name, &quot;小华&quot;);    s1.sex = MAN;    s1.sc.intScore = 90;    s1.sc.floatScore = 90.5f; // 覆盖intScore内存    Student arr[2] = &#123;s1, &#123;&quot;小丽&quot;, WOMAN, &#123;85&#125;&#125;&#125;;    showStu(arr[0]);    showStu(arr[1]);    return 0;&#125;
六、综合实战：学生成绩管理系统
#include &lt;stdio.h&gt;#include &lt;string.h&gt;// 枚举：性别enum Gender &#123; MALE, FEMALE &#125;;// 枚举：学科enum Subject &#123; CHINESE, MATH, ENGLISH &#125;;// 联合体：成绩union Grade &#123;    int score;      // 百分制成绩    char level;     // 等级制成绩（A/B/C/D）&#125;;// 结构体：学生typedef struct &#123;    int id;    char name[20];    enum Gender gender;    enum Subject subject;    union Grade grade;    int grade_type;  // 0:百分制, 1:等级制&#125; Student;// 显示学生信息void display_student(Student s) &#123;    printf(&quot;学号: %d\n&quot;, s.id);    printf(&quot;姓名: %s\n&quot;, s.name);    printf(&quot;性别: %s\n&quot;, s.gender == MALE ? &quot;男&quot; : &quot;女&quot;);        // 显示学科    switch(s.subject) &#123;        case CHINESE: printf(&quot;学科: 语文\n&quot;); break;        case MATH:    printf(&quot;学科: 数学\n&quot;); break;        case ENGLISH: printf(&quot;学科: 英语\n&quot;); break;    &#125;        // 显示成绩    if (s.grade_type == 0) &#123;        printf(&quot;成绩: %d分\n&quot;, s.grade.score);    &#125; else &#123;        printf(&quot;等级: %c\n&quot;, s.grade.level);    &#125;    printf(&quot;--------------------\n&quot;);&#125;// 修改成绩void modify_grade(Student *s, int new_score) &#123;    s-&gt;grade.score = new_score;    s-&gt;grade_type = 0;&#125;int main() &#123;    // 创建学生    Student s1 = &#123;        .id = 1001,        .name = &quot;张三&quot;,        .gender = MALE,        .subject = MATH,        .grade.score = 95,        .grade_type = 0    &#125;;        Student s2 = &#123;        .id = 1002,        .name = &quot;李四&quot;,        .gender = FEMALE,        .subject = ENGLISH,        .grade.level = &#x27;A&#x27;,        .grade_type = 1    &#125;;        // 显示信息    display_student(s1);    display_student(s2);        // 修改成绩    modify_grade(&amp;s1, 100);    printf(&quot;修改后:\n&quot;);    display_student(s1);        return 0;&#125;
七、四大自定义类型对比总结



类型
内存特点
使用场景




struct结构体
成员独立内存，空间累加
存储一组关联不同类型数据


union联合体
成员共享同一块内存
节省内存、大小端判断、多类型复用


enum枚举
常量映射整数，占用int
固定有限取值（状态、星期、性别）


typedef
仅别名，不创建新类型
简化长类型名、提升代码移植性

MySQL常见命令操作手册
一、基础数据库、表操作命令
1. 数据库操作
-- 查看所有数据库show databases;-- 创建名为students数据库create database students;-- 进入/使用指定数据库use students;-- 查询当前所在数据库select database();-- 删除数据库drop database students;-- 查看数据库数据保存目录show variables like &quot;datadir&quot;;-- 查看数据库字符集show variables like &#x27;%char%&#x27;;-- 创建带特殊字符的数据库（反引号包裹名称）create database `student-new`;
2. 数据表基础操作
-- 查看当前库所有表show tables;-- 创建t1表，id、name字段create table t1 (id varchar(20),name varchar(20));-- 查看表字段结构desc t1;-- 删除整张表drop table t1;-- 修改表名alter table class1 rename class01;-- 清空表内所有数据（保留表结构）delete from t1;
3. 表结构修改 alter table
-- 修改字段长度alter table t1 modify column name varchar(20);-- 新增字段alter table students add address varchar(20) not null;-- 新增字段放在首位alter table class01 add uid int(20) first;-- 新增字段指定在某个字段后alter table class01 add address varchar(30) after age;-- 删除指定字段alter table students drop address;
4. 数据增删改查（DML基础）
插入数据 insert
-- 全字段插入单条数据insert into t1 values (&quot;1&quot;,&quot;mzj&quot;);-- 一次性插入多条数据insert into sunwukong values(1,&#x27;dasheng&#x27;,800,&#x27;jindouyun&#x27;),(2,&#x27;xingzhe&#x27;,800,&#x27;bianhua&#x27;),(3,&#x27;zhexing&#x27;,800,&#x27;jingubang&#x27;);
查询数据 select
-- 查询表全部数据select * from t1;-- 查询指定字段select id from t1;select name,skill from sunwukong;-- 多条件筛选查询（字符串标准用单引号）select * from t1 where id=1 and name=&#x27;mzj&#x27;;-- NULL值判断不能用=，使用is null / is not null-- 跨库查询表数据select * from 数据库名.表名;
更新数据 update
-- 根据条件修改指定字段update t1 set name=&#x27;lisi&#x27; where id=1;
删除数据 delete
-- 删除整张表所有数据delete from t1;-- 根据条件删除单行数据delete from t1 where name=&#x27;zhangsan&#x27;;-- 删除空字符串数据delete from sunwukong where skill=&#x27;&#x27;;
5. 存储引擎相关命令
-- 查看所有支持的存储引擎show engines;-- 查看当前默认存储引擎show variables like &#x27;%storage_engine%&#x27;;-- 修改指定表的存储引擎alter table t1 engine=innodb;
